
package com.example.taxgap.controller; import com.example.taxgap.config.JwtUtils; import com.example.taxgap.domain.dto.auth.*; import com.example.taxgap.domain.entity.User; import com.example.taxgap.repository.UserRepository; import org.springframework.beans.factory.annotation.Value; import org.springframework.http.ResponseEntity; import org.springframework.security.crypto.password.PasswordEncoder; import org.springframework.web.bind.annotation.*; import java.util.*; import java.util.stream.Collectors;
@RestController @RequestMapping("/auth") public class AuthController { private final UserRepository userRepo; private final PasswordEncoder encoder; private final JwtUtils jwt; public AuthController(UserRepository u, PasswordEncoder e, @Value("${security.jwt.secret}") String s, @Value("${security.jwt.expiryMinutes}") long exp){ userRepo=u; encoder=e; jwt=new JwtUtils(s,exp);} @PostMapping("/login") public ResponseEntity<?> login(@RequestBody LoginRequest req){ User u=userRepo.findByUsername(req.getUsername()).orElse(null); if(u==null || !u.isEnabled() || !encoder.matches(req.getPassword(), u.getPassword())) return ResponseEntity.status(401).body(Map.of("error","Invalid credentials")); Set<String> roles=u.getRoles().stream().map(r->r.getName()).collect(Collectors.toSet()); String token=jwt.generate(u.getUsername(), Map.of("roles", roles)); return ResponseEntity.ok(new LoginResponse(token, u.getUsername(), roles)); } }
